// Command migrate applies the versioned SQL migrations in /api/migrations
// (golang-migrate format, generated by cmd/migrategen plus handwritten files).
package main

import (
	"errors"
	"flag"
	"fmt"
	"log"

	"github.com/golang-migrate/migrate/v4"
	_ "github.com/golang-migrate/migrate/v4/database/postgres"
	_ "github.com/golang-migrate/migrate/v4/source/file"

	"ksdevworks/ecommerce/api/internal/config"
)

func main() {
	direction := flag.String("direction", "up", "up | down | version")
	steps := flag.Int("steps", 0, "number of down steps (0 with -direction=down rolls back everything)")
	dbURL := flag.String("db", "", "database URL override (defaults to DATABASE_URL)")
	src := flag.String("path", "migrations", "migrations directory")
	flag.Parse()

	cfg, err := config.Load()
	if err != nil {
		log.Fatalf("config: %v", err)
	}
	url := cfg.DatabaseURL
	if *dbURL != "" {
		url = *dbURL
	}
	if url == "" {
		log.Fatal("DATABASE_URL is required")
	}

	m, err := migrate.New("file://"+*src, url)
	if err != nil {
		log.Fatalf("migrate init: %v", err)
	}
	defer func() { _, _ = m.Close() }()

	switch *direction {
	case "up":
		err = m.Up()
	case "down":
		if *steps > 0 {
			err = m.Steps(-*steps)
		} else {
			err = m.Down()
		}
	case "version":
		v, dirty, verr := m.Version()
		if verr != nil && !errors.Is(verr, migrate.ErrNilVersion) {
			log.Fatalf("version: %v", verr)
		}
		fmt.Printf("version=%d dirty=%v\n", v, dirty)
		return
	default:
		log.Fatalf("unknown -direction %q", *direction)
	}

	if err != nil && !errors.Is(err, migrate.ErrNoChange) {
		log.Fatalf("migrate %s: %v", *direction, err)
	}
	v, dirty, verr := m.Version()
	if verr != nil && !errors.Is(verr, migrate.ErrNilVersion) {
		log.Fatalf("version: %v", verr)
	}
	log.Printf("migrate %s done (version=%d dirty=%v)", *direction, v, dirty)
}
